{
var input = inputs.Length > 0 ? inputs[0] : null;
        if (input is null)
            return PixelBuffer.CreateSolid(context.TileSize, context.TileSize, 0, 0, 0);

        var blockSize = Math.Max(1, GetInt(parameters, "blockSize", 2));
        var paletteSteps = GetInt(parameters, "paletteSteps", 0);
        var sampleMode = GetChoice(parameters, "sampleMode", "center");
        var ditherMode = GetChoice(parameters, "ditherMode", "none");
        var outlineStrength = GetFloat(parameters, "outlineStrength", 0f);
        var outlineColor = GetColor(parameters, "outlineColor", System.Windows.Media.Color.FromRgb(0, 0, 0));
        var outR = outlineColor.R / 255f;
        var outG = outlineColor.G / 255f;
        var outB = outlineColor.B / 255f;

        var w = input.Width;
        var h = input.Height;
        var result = new PixelBuffer(w, h);

        // Ordered dither matrix
        var ditherMatrix = new float[,]
        {
            { 0f / 16f, 8f / 16f, 2f / 16f, 10f / 16f },
            { 12f / 16f, 4f / 16f, 14f / 16f, 6f / 16f },
            { 3f / 16f, 11f / 16f, 1f / 16f, 9f / 16f },
            { 15f / 16f, 7f / 16f, 13f / 16f, 5f / 16f }
        };

        result.ParallelForEachPixel((x, y) =>
        {
            float r, g, b, a;

            if (sampleMode == "average" && blockSize > 1)
            {
                // Average all pixels in the block
                float sr = 0, sg = 0, sb = 0, sa = 0;
                var bx0 = (x / blockSize) * blockSize;
                var by0 = (y / blockSize) * blockSize;
                var count = 0;
                for (var by = by0; by < Math.Min(by0 + blockSize, h); by++)
                {
                    for (var bx = bx0; bx < Math.Min(bx0 + blockSize, w); bx++)
                    {
                        var (pr, pg, pb, pa) = input.GetPixel(bx, by);
                        sr += pr; sg += pg; sb += pb; sa += pa;
                        count++;
                    }
                }
                r = sr / count; g = sg / count; b = sb / count; a = sa / count;
            }
            else
            {
                // Center or nearest sampling
                var bx = (x / blockSize) * blockSize + blockSize / 2;
                var by = (y / blockSize) * blockSize + blockSize / 2;
                bx = Math.Min(bx, w - 1);
                by = Math.Min(by, h - 1);
                (r, g, b, a) = input.GetPixel(bx, by);
            }

            // Dithering before palette quantization
            if (ditherMode == "ordered4x4" && paletteSteps > 1)
            {
                var steps = paletteSteps - 1f;
                var ditherVal = (ditherMatrix[y % 4, x % 4] - 0.5f) / steps;
                r += ditherVal;
                g += ditherVal;
                b += ditherVal;
            }

            // Palette quantization (skip for FS — handled in serial pass)
            if (paletteSteps > 1 && ditherMode != "floydSteinberg")
            {
                var steps = paletteSteps - 1f;
                r = MathF.Round(r * steps) / steps;
                g = MathF.Round(g * steps) / steps;
                b = MathF.Round(b * steps) / steps;
            }

            result.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), a);
        });

        // Floyd-Steinberg error diffusion (serial scanline — incompatible with ParallelForEachPixel)
        if (ditherMode == "floydSteinberg" && paletteSteps > 1)
        {
            ApplyFloydSteinbergInPlace(result, paletteSteps, w, h);
        }

        // Outline pass: detect color boundaries between adjacent pixels at block edges
        if (outlineStrength > 0f && blockSize > 1)
        {
            var outlined = result.Clone();
            outlined.ParallelForEachPixel((x, y) =>
            {
                var (cr, cg, cb, ca) = result.GetPixel(x, y);
                float maxDiff = 0f;

                // Check all four immediate neighbors; after pixelation only block-boundary
                // neighbors can differ in color.
                if (x + 1 < w)
                {
                    var (rr, rg, rb, _) = result.GetPixel(x + 1, y);
                    maxDiff = MathF.Max(maxDiff, MathF.Abs(cr - rr) + MathF.Abs(cg - rg) + MathF.Abs(cb - rb));
                }
                if (x - 1 >= 0)
                {
                    var (lr, lg, lb, _) = result.GetPixel(x - 1, y);
                    maxDiff = MathF.Max(maxDiff, MathF.Abs(cr - lr) + MathF.Abs(cg - lg) + MathF.Abs(cb - lb));
                }
                if (y + 1 < h)
                {
                    var (dr, dg, db, _) = result.GetPixel(x, y + 1);
                    maxDiff = MathF.Max(maxDiff, MathF.Abs(cr - dr) + MathF.Abs(cg - dg) + MathF.Abs(cb - db));
                }
                if (y - 1 >= 0)
                {
                    var (ur, ug, ub, _) = result.GetPixel(x, y - 1);
                    maxDiff = MathF.Max(maxDiff, MathF.Abs(cr - ur) + MathF.Abs(cg - ug) + MathF.Abs(cb - ub));
                }

                var edge = Math.Clamp(maxDiff * 3f, 0f, 1f) * outlineStrength;

                if (edge > 0.01f)
                {
                    var fr = Lerp(cr, outR, edge);
                    var fg = Lerp(cg, outG, edge);
                    var fb = Lerp(cb, outB, edge);
                    outlined.SetPixel(x, y, fr, fg, fb, ca);
                }
            });
            return outlined;
        }

        return result;

    private static new float Lerp(float a, float b, float t) => a + (b - a) * t;

    private static void ApplyFloydSteinbergInPlace(PixelBuffer buffer, int paletteSteps, int w, int h)
    {
        var steps = paletteSteps - 1f;
        for (var y = 0; y < h; y++)
        {
            for (var x = 0; x < w; x++)
            {
                var (r, g, b, a) = buffer.GetPixel(x, y);

                // Quantize
                var rq = MathF.Round(r * steps) / steps;
                var gq = MathF.Round(g * steps) / steps;
                var bq = MathF.Round(b * steps) / steps;
                buffer.SetPixel(x, y, rq, gq, bq, a);

                // Quantization error
                var er = r - rq;
                var eg = g - gq;
                var eb = b - bq;

                // Distribute error to future pixels (Floyd-Steinberg kernel)
                if (x + 1 < w)
                    AddError(buffer, x + 1, y, er * 7f / 16f, eg * 7f / 16f, eb * 7f / 16f);

                if (y + 1 < h)
                {
                    if (x - 1 >= 0)
                        AddError(buffer, x - 1, y + 1, er * 3f / 16f, eg * 3f / 16f, eb * 3f / 16f);
                    AddError(buffer, x, y + 1, er * 5f / 16f, eg * 5f / 16f, eb * 5f / 16f);
                    if (x + 1 < w)
                        AddError(buffer, x + 1, y + 1, er * 1f / 16f, eg * 1f / 16f, eb * 1f / 16f);
                }
            }
        }
    }

    private static void AddError(PixelBuffer buffer, int x, int y, float er, float eg, float eb)
    {
        var (r, g, b, a) = buffer.GetPixel(x, y);
        buffer.SetPixel(x, y, Math.Clamp(r + er, 0f, 1f), Math.Clamp(g + eg, 0f, 1f), Math.Clamp(b + eb, 0f, 1f), a);
    }
